local key = KEYS[1]
local window_sec = tonumber(ARGV[1])
local limit = tonumber(ARGV[2])
local incr = tonumber(ARGV[3])

-- Get current time from Redis (server‑side) to tolerate ±2 s clock drift
local time = redis.call('TIME')
local now_sec = time[1]
local now_usec = time[2]
local now_ms = now_sec * 1000 + math.floor(now_usec / 1000)
local window_ms = window_sec * 1000

-- 1) Prune entries older than the window (atomic with counting)
redis.call('ZREMRANGEBYSCORE', key, '-inf', now_ms - window_ms)

-- 2) Count current entries inside the window
local count = redis.call('ZCARD', key)

local allowed = 0
if count < limit then
    if incr == 1 then
        -- Add a unique entry (timestamp:random) for this request
        local member = now_ms .. ':' .. math.random(1000000)
        redis.call('ZADD', key, now_ms, member)
        count = count + 1
    end
    allowed = 1
end

-- 3) Compute remaining requests and reset time in the same pass
local remaining = limit - count
if remaining < 0 then remaining = 0 end

local oldest = redis.call('ZRANGE', key, 0, 0, 'WITHSCORES')
local reset_at = 0
if #oldest > 0 then
    local oldest_score = tonumber(oldest[2])
    reset_at = oldest_score + window_ms
