}

// NewBoundedWorkerPool creates a new pool with w workers and a queue that can
// hold up to q pending tasks. Both w and q must be positive.
func NewBoundedWorkerPool(w, q int) *BoundedWorkerPool {
	if w <= 0 || q <= 0 {
		panic("worker pool: both worker count and queue size must be > 0")
	}
	p := &BoundedWorkerPool{
		numWorkers: w,
		queueSize:  q,
		taskChan:   make(chan task, q),
		stopChan:   make(chan struct{}),
	}
	// Start the fixed set of workers.
	for i := 0; i < w; i++ {
		p.wg.Add(1)
		go p.worker()
	}
	return p
}

// task couples a function to its result channel.
type task struct {
	fn   func() error
	errCh chan<- error
}

// Submit submits a task to the pool. It returns a channel that will
// receive the task's result (nil on success, error otherwise) and a possible
// error. If the pool is saturated (queue full) or closed, Submit returns
// ErrPoolFull or ErrPoolClosed respectively and the returned channel is nil.
// The provided context is inspected only for cancellation before the task is
// queued; it is not passed to the task function.
func (p *BoundedWorkerPool) Submit(ctx context.Context, fn func() error) (<-chan error, error) {
