			// Shutdown has been requested; exit gracefully.
			return
		case t := <-p.taskChan:
			p.addQueueDepth(-1) // one fewer task waiting
			p.addInFlight(1)
			p.executeTask(t)
			p.addInFlight(-1)
		}
	}
}

// executeTask runs the provided task, recovers from panics, and sends the
// result (or panic error) on the task's error channel.
func (p *BoundedWorkerPool) executeTask(t task) {
	defer func() {
		if r := recover(); r != nil {
			// Propagate the panic as an error.
			err := &PanicError{Panic: r}
			select {
			case t.errCh <- err:
			default:
				// If the channel is already closed (caller cancelled), drop.
			}
			p.addPanics(1)
			p.addCompleted(1) // count as completed even though it panicked
		}
	}()

	// Execute the task.
	var err error
	if t.fn != nil {
		err = t.fn()
	}
	// Send the result; non‑blocking in case the caller abandoned the channel.
	select {
	case t.errCh <- err:
	default:
		// Channel already closed; ignore.
	}
	p.addCompleted(1)
}

// PanicError wraps a recovered panic value.
type PanicError struct {
	Panic interface{}
}

func (p *PanicError) Error() string {
	return "panic in worker pool task"
}

